mapper.select:
SELECT A.write_year , A.doc_type , A.doc_no , A.process_id , B.process_nm , A.comp_id , A.rev_no , A.material , A.product , A.worker_cnt , A.created_at , A.created_by , A.updated_at , A.updated_by FROM esg.tb_safety_and_health_info_survey A LEFT JOIN esg.tb_process_info B ON A.process_id = B.process_id WHERE A.write_year = #{writeYear} AND A.doc_type = #{docType} AND A.doc_no IN
#{docNo}
AND A.comp_id = #{compId}

mapper.update:
UPDATE esg.tb_safety_and_health_info_survey
   SET
		confirm_yn = #{confirmYn},

			confirm_dt = now(),


			confirm_dt = null,

		updated_at = now(),
		updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}

UPDATE esg.tb_safety_and_health_info_survey
   SET material = #{material}
   	 , product = #{product}
   	 , worker_cnt = #{workerCnt}
   	 , use_yn = #{useYn}
     , updated_at = now()
     , updated_by = #{updatedBy}
     , write_dt = #{writeDt}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}

UPDATE esg.tb_safety_and_health_info_survey
   SET use_yn = 'N'
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}

UPDATE esg.tb_safety_and_health_info_survey_detail
   SET work_type = #{workType}
     , content = #{content}
     , desc1 = #{desc1}
     , desc2 = #{desc2}
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND prcs_work_id = #{prcsWorkId}
   AND work_detail_id = #{workDetailId}

UPDATE esg.tb_safety_and_health_info_survey_detail
   SET use_yn = #{useYn}
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND prcs_work_id = #{prcsWorkId}
   AND work_detail_id = #{workDetailId}

